UPDATE TBL_PVE_BATTLE_SESSION
SET
    CURRENT_SET = #{currentSet},
    MY_WINS = #{myWins},
    AI_WINS = #{aiWins},
    GAME_STATE_DATA = #{gameStateData} WHERE
    USER_ID = #{userId}
    AND STAGE_LEVEL = #{stageLevel}
    AND SUB_LEVEL = #{subLevel}
    AND STATUS = 'IN_PROGRESS'

DELETE FROM TBL_PVE_BATTLE_SESSION
WHERE USER_ID = #{userId}
  AND STAGE_LEVEL = #{stageLevel}
  AND SUB_LEVEL = #{subLevel}
  AND STATUS = 'COMPLETED'

UPDATE TBL_PVE_BATTLE_SESSION
SET
    STATUS = 'COMPLETED',
    MY_WINS = #{myWins},
    AI_WINS = #{aiWins}
WHERE
    USER_ID = #{userId}
    AND STAGE_LEVEL = #{stageLevel}
    AND SUB_LEVEL = #{subLevel}
    AND STATUS = 'IN_PROGRESS'

